import{t as l,getLocale as v}from"./i18n.CQj9Tpoy.js";async function p(){const s=document.getElementById("archives-list");if(!s)return;const u=v();try{const i=await(await fetch("/api/v1/articles?page_size=1000&status=published")).json();if(i.code===0&&i.data){const d=i.data.items;if(d.length===0){s.innerHTML=`<p style="text-align:center;color:var(--color-text-tertiary);padding:3rem 0;">${l("article.no_articles")}</p>`;return}const r={};for(const a of d){const n=a.published_at||a.created_at,c=new Date(n),t=c.getFullYear().toString(),e=(c.getMonth()+1).toString().padStart(2,"0");r[t]||(r[t]={}),r[t][e]||(r[t][e]=[]),r[t][e].push(a)}let o="";const m=Object.keys(r).sort((a,n)=>Number(n)-Number(a));for(const a of m){const n=Object.values(r[a]).reduce((t,e)=>t+e.length,0);o+='<div class="archive-year-group">',o+=`<h2 class="archive-year">${a}<span class="archive-year-count">${n} ${u==="zh"?"篇":"articles"}</span></h2>`;const c=Object.keys(r[a]).sort((t,e)=>Number(e)-Number(t));for(const t of c){o+='<div class="archive-month-group">',o+=`<h3 class="archive-month">${l(`month.${t}`)}</h3>`,o+='<ul class="archive-list">';for(const e of r[a][t]){const h=new Date(e.published_at||e.created_at),f=`${(h.getMonth()+1).toString().padStart(2,"0")}-${h.getDate().toString().padStart(2,"0")}`;o+=`<li><span class="archive-date">${f}</span><a href="/articles/${e.slug}">${e.title}</a></li>`}o+="</ul></div>"}o+="</div>"}s.innerHTML=o}}catch{s.innerHTML=`<p style="text-align:center;color:var(--color-text-tertiary);padding:3rem 0;">${l("common.load_failed")}</p>`}}p();document.addEventListener("locale-changed",()=>p());
